    private final Map<String, Consumer<String>> strategies = new HashMap<>();
    public TranscoderStrategy482() {
        strategies.put("h264",
            video -> System.out.println("H264 transcode: " + video));
        strategies.put("h265",
            video -> System.out.println("H265 transcode: " + video));
    }
    public void register(String name, Consumer<String> strategy) {
        strategies.put(name, strategy);
    }
    public void execute(String name, String video) {
        Consumer<String> s = strategies.get(name);
        if (s == null) throw new IllegalArgumentException("Unknown strategy: " + name);
        s.accept(video);
    }
}

